3	type Step = { op: string; items: { type: string }[] };
4	
5	type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	type StepResult = { premium: number };
11	
12	type ScenarioResult = {
13	  results: StepResult[];
14	};
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const PROCESSING_FEE = 5;
26	
27	const RUNE_BLOCK_SIZE = 3;
28	const RUNE_BLOCK_BASE_PREMIUM = 60;
29	
30	const calculateTotalBasePremium = (items: Step["items"]): number =>
31	  items.length === RUNE_BLOCK_SIZE
32	    ? RUNE_BLOCK_BASE_PREMIUM
33	    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
34	
35	const quoteStep = (step: Step): StepResult => {
36	  const totalBasePremium = calculateTotalBasePremium(step.items);
37	  const firstInsuranceSurcharge =
38	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
39	  return {
40	    premium: Math.ceil(
41	      totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
42	    ),
43	  };
44	};
45	
46	export const processScenario = (scenario: Scenario): ScenarioResult => ({
47	  results: scenario.steps.map(quoteStep),
48	});
49

