const isRuneBlock = (items: Step["items"]): boolean =>
  items.length === RUNE_BLOCK_SIZE;

const calculateTotalBasePremium = (items: Step["items"]): number =>
  isRuneBlock(items)
    ? RUNE_BLOCK_BASE_PREMIUM
    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
